-- V5 sustainability seeds aligned to schema_unified.sql
-- Excludes CAT_ACCESS. Accessibility is seeded separately.

BEGIN;

-- 1) Classification schemes for sustainability-related labels
WITH src(code, name, description, selection, display_group, is_distinction, name_i18n, metadata) AS (
VALUES
  ('LBL_ATR', 'ATR - Agir pour un Tourisme Responsable', 'Référentiel structuré en 3 axes, 16 critères et 42 indicateurs.', 'single', 'sustainability_labels', TRUE, '{"fr": "ATR - Agir pour un Tourisme Responsable"}'::jsonb, '{"official_source_url": "https://www.tourisme-responsable.org/", "scope": "label"}'::jsonb),
  ('LBL_CLEF_VERTE', 'Clef Verte', 'Référentiel par typologie, environ 120 critères en 7 catégories avec impératifs et conseillés.', 'single', 'sustainability_labels', TRUE, '{"fr": "Clef Verte"}'::jsonb, '{"official_source_url": "https://www.laclefverte.org/", "scope": "label"}'::jsonb),
  ('LBL_DESTINATION_EXCELLENCE', 'Destination d''excellence', 'Label d''État remplaçant Qualité Tourisme, avec pilier Qualité et pilier Écoresponsable.', 'single', 'sustainability_labels', TRUE, '{"fr": "Destination d''excellence"}'::jsonb, '{"official_source_url": "https://www.economie.gouv.fr/entreprises/developper-son-entreprise/labels-qualite-et-valorisation-du-savoir-faire/destination", "scope": "label"}'::jsonb),
  ('LBL_ECO_LABEL_UE', 'Écolabel européen - hébergement touristique', 'Critères obligatoires et critères optionnels à points, minimum de 20 points.', 'single', 'sustainability_labels', TRUE, '{"fr": "Écolabel européen - hébergement touristique"}'::jsonb, '{"official_source_url": "https://environment.ec.europa.eu/topics/circular-economy/eu-ecolabel-home/eu-ecolabel-tourist-accommodation_en", "scope": "label"}'::jsonb),
  ('LBL_FLOCON_VERT', 'Flocon Vert', 'Label et démarche de progrès pour les destinations de montagne engagées dans la transition écologique et sociale.', 'single', 'sustainability_labels', TRUE, '{"fr": "Flocon Vert"}'::jsonb, '{"official_source_url": "https://www.flocon-vert.org/", "scope": "label"}'::jsonb),
  ('LBL_GREEN_DESTINATIONS', 'Green Destinations', 'Programme international de certification et d’awards pour les destinations touristiques durables.', 'single', 'sustainability_labels', TRUE, '{"fr": "Green Destinations"}'::jsonb, '{"official_source_url": "https://www.greendestinations.org/", "scope": "label"}'::jsonb),
  ('LBL_LABEL_BAS_CARBONE', 'Label bas-carbone', 'Cadre national de certification de projets de réduction ou séquestration d’émissions.', 'single', 'sustainability_labels', TRUE, '{"fr": "Label bas-carbone"}'::jsonb, '{"official_source_url": "https://label-bas-carbone.ecologie.gouv.fr/", "scope": "label"}'::jsonb),
  ('LBL_PAVILLON_BLEU', 'Pavillon Bleu', 'Label international de tourisme durable pour les plages et les ports de plaisance ; critères eau, déchets, biodiversité, sécurité, sensibilisation.', 'single', 'sustainability_labels', TRUE, '{"fr": "Pavillon Bleu"}'::jsonb, '{"official_source_url": "https://pavillonbleu.org/", "scope": "label"}'::jsonb),
  ('LBL_QUALITE_TOURISME', 'Qualité Tourisme', 'Label en gestion extinctive jusqu''au 31 décembre 2026, inclus uniquement pour reprise historique. Gestion extinctive jusqu’au 31/12/2026.', 'single', 'sustainability_labels', TRUE, '{"fr": "Qualité Tourisme"}'::jsonb, '{"official_source_url": "https://www.atout-france.fr/fr/qualite-tourisme", "scope": "label"}'::jsonb)
)
INSERT INTO ref_classification_scheme (code, name, description, selection, display_group, is_distinction, name_i18n)
SELECT code, name, description, selection, display_group, is_distinction, name_i18n
FROM src
ON CONFLICT (code) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  selection = EXCLUDED.selection,
  display_group = EXCLUDED.display_group,
  is_distinction = EXCLUDED.is_distinction,
  name_i18n = EXCLUDED.name_i18n,
  updated_at = NOW();

-- Store source metadata in extra when available
WITH src(code, metadata) AS (
VALUES
  ('LBL_ATR', '{"official_source_url": "https://www.tourisme-responsable.org/", "scope": "label"}'::jsonb),
  ('LBL_CLEF_VERTE', '{"official_source_url": "https://www.laclefverte.org/", "scope": "label"}'::jsonb),
  ('LBL_DESTINATION_EXCELLENCE', '{"official_source_url": "https://www.economie.gouv.fr/entreprises/developper-son-entreprise/labels-qualite-et-valorisation-du-savoir-faire/destination", "scope": "label"}'::jsonb),
  ('LBL_ECO_LABEL_UE', '{"official_source_url": "https://environment.ec.europa.eu/topics/circular-economy/eu-ecolabel-home/eu-ecolabel-tourist-accommodation_en", "scope": "label"}'::jsonb),
  ('LBL_FLOCON_VERT', '{"official_source_url": "https://www.flocon-vert.org/", "scope": "label"}'::jsonb),
  ('LBL_GREEN_DESTINATIONS', '{"official_source_url": "https://www.greendestinations.org/", "scope": "label"}'::jsonb),
  ('LBL_LABEL_BAS_CARBONE', '{"official_source_url": "https://label-bas-carbone.ecologie.gouv.fr/", "scope": "label"}'::jsonb),
  ('LBL_PAVILLON_BLEU', '{"official_source_url": "https://pavillonbleu.org/", "scope": "label"}'::jsonb),
  ('LBL_QUALITE_TOURISME', '{"official_source_url": "https://www.atout-france.fr/fr/qualite-tourisme", "scope": "label"}'::jsonb)
)
UPDATE ref_classification_scheme s
SET description = COALESCE(s.description, s.description),
    updated_at = NOW()
FROM src
WHERE s.code = src.code;

-- 2) Singleton values per scheme, required by object_classification(value_id)
WITH src(scheme_code, code, name, position, name_i18n, metadata) AS (
VALUES
  ('LBL_ATR', 'granted', 'Titulaire ATR - Agir pour un Tourisme Responsable', 1, '{"fr": "Titulaire ATR - Agir pour un Tourisme Responsable"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_ATR"}'::jsonb),
  ('LBL_CLEF_VERTE', 'granted', 'Titulaire Clef Verte', 1, '{"fr": "Titulaire Clef Verte"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_CLEF_VERTE"}'::jsonb),
  ('LBL_DESTINATION_EXCELLENCE', 'granted', 'Titulaire Destination d''excellence', 1, '{"fr": "Titulaire Destination d''excellence"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_DESTINATION_EXCELLENCE"}'::jsonb),
  ('LBL_ECO_LABEL_UE', 'granted', 'Titulaire Écolabel européen - hébergement touristique', 1, '{"fr": "Titulaire Écolabel européen - hébergement touristique"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_ECO_LABEL_UE"}'::jsonb),
  ('LBL_FLOCON_VERT', 'granted', 'Titulaire Flocon Vert', 1, '{"fr": "Titulaire Flocon Vert"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_FLOCON_VERT"}'::jsonb),
  ('LBL_GREEN_DESTINATIONS', 'granted', 'Titulaire Green Destinations', 1, '{"fr": "Titulaire Green Destinations"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_GREEN_DESTINATIONS"}'::jsonb),
  ('LBL_LABEL_BAS_CARBONE', 'granted', 'Titulaire Label bas-carbone', 1, '{"fr": "Titulaire Label bas-carbone"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_LABEL_BAS_CARBONE"}'::jsonb),
  ('LBL_PAVILLON_BLEU', 'granted', 'Titulaire Pavillon Bleu', 1, '{"fr": "Titulaire Pavillon Bleu"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_PAVILLON_BLEU"}'::jsonb),
  ('LBL_QUALITE_TOURISME', 'granted', 'Titulaire Qualité Tourisme', 1, '{"fr": "Titulaire Qualité Tourisme"}'::jsonb, '{"kind": "label_status", "label_code": "LBL_QUALITE_TOURISME"}'::jsonb)
)
INSERT INTO ref_classification_value (scheme_id, code, name, position, name_i18n, metadata)
SELECT s.id, src.code, src.name, src.position, src.name_i18n, src.metadata
FROM src
JOIN ref_classification_scheme s ON s.code = src.scheme_code
ON CONFLICT (scheme_id, code) DO UPDATE SET
  name = EXCLUDED.name,
  position = EXCLUDED.position,
  name_i18n = EXCLUDED.name_i18n,
  metadata = EXCLUDED.metadata,
  updated_at = NOW();

